import React from "react";
import PropTypes from "prop-types";

const MissionItem = ({ mission, onUpdateProgress, onClaimReward }) => {
  const {
    mission_id,
    name,
    description,
    progress,
    target,
    completed,
    claimed,
  } = mission;

  const handleProgressChange = (e) => {
    const newProgress = parseInt(e.target.value, 10);
    onUpdateProgress(mission_id, newProgress);
  };

  const handleClaim = () => {
    onClaimReward(mission_id);
  };

  return (
    <li key={mission_id}>
      <h3>{name}</h3>
      <p>{description}</p>
      <p>
        Progress: {progress} / {target}
      </p>
      {completed && !claimed ? (
        <button onClick={handleClaim}>Claim Reward</button>
      ) : (
        <button disabled>Reward Claimed</button>
      )}
      <input
        type="number"
        value={progress}
        onChange={handleProgressChange}
        max={target}
        min={0}
      />
    </li>
  );
};

MissionItem.propTypes = {
  mission: PropTypes.object.isRequired,
  onUpdateProgress: PropTypes.func.isRequired,
  onClaimReward: PropTypes.func.isRequired,
};

export default MissionItem;
